#graphql
  mutation BlogCreate($blog: BlogCreateInput!) {
    blogCreate(blog: $blog) {
      blog {
        id
        title
        handle
        createdAt
        updatedAt
        commentPolicy
        templateSuffix
        tags
        articlesCount { count precision }
      }
      userErrors { field message }
    }
  }

